# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

def process_transaction(transaction):
    accounts = {
        "checking": 1000.0,
        "savings": 500.0,
        "credit_card": -2000.0
    }

    if transaction["type"] == "deposit":
        accounts[transaction["account"]] += transaction["amount"]
    elif transaction["type"] == "withdrawal":
        if accounts[transaction["account"]] >= abs(transaction["amount"]):
            accounts[transaction["account"]] -= transaction["amount"]
        else:
            print("Insufficient funds")
    elif transaction["type"] == "transfer":
        source_account = transaction["source_account"]
        destination_account = transaction["destination_account"]
        
        if accounts[source_account] >= transaction["amount"]:
            accounts[source_account] -= transaction["amount"]
            accounts[destination_account] += transaction["amount"]
        else:
            print("Insufficient funds")

    return accounts

transactions = [
    {"type": "deposit", "account": "checking", "amount": 500.0},
    {"type": "withdrawal", "account": "savings", "amount": 200.0},
    {"type": "transfer", "source_account": "checking", "destination_account": "savings", "amount": 300.0}
]

final_accounts = {}
for transaction in transactions:
    final_accounts = process_transaction(transaction)

print(final_accounts)